You are an implementer subagent. Create the DailyReportAiEmailController and its route config for the oa-server project.

## Context

This is an OA system. We need a controller for managing AI daily report email tasks (CRUD + toggle). The controller uses whitelist-based access control with hardcoded sfuser_id array.

The base Controller class at `D:\project\info-gitlab\oa\oa-server\app\Http\Controllers\Controller.php` uses `ResponseTrait` which provides:
- `$this->responseJsonSuccess($data)` — returns JSON with error_code=0
- `$this->responseJsonFail($message)` — returns JSON with error message

The table `daily_report_ai_email_tasks` has columns: id, sfuser_id, name, dimension, report_range, send_cycle, send_time, system_prompt, is_on, created_at, updated_at, deleted_at.

The `sfuser_info` param is injected by the oa-core proxy layer. Access the user ID via `Arr::get($request->input('sfuser_info'), 'id')`.

Existing controller pattern: see `D:\project\info-gitlab\oa\oa-server\app\Http\Controllers\Oa\DailyReportAiController.php` for reference style (read it for patterns like DB usage, constructor, etc.).

## Files to create

### 1. `D:\project\info-gitlab\oa\oa-server\app\Http\Controllers\Oa\DailyReportAiEmailController.php`

```php
<?php

namespace App\Http\Controllers\Oa;

use App\Http\Controllers\Controller;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;
use Illuminate\Support\Arr;
use Illuminate\Support\Facades\DB;

class DailyReportAiEmailController extends Controller
{
    // 白名单用户 ID
    private const WHITELIST_IDS = [85091, 232753];

    private function inWhitelist(int $sfuserId): bool
    {
        return in_array($sfuserId, self::WHITELIST_IDS);
    }

    public function taskList(Request $request): JsonResponse
    {
        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
        if (!$this->inWhitelist($sfuserId)) {
            return $this->responseJsonFail('无权限');
        }

        $list = DB::table('daily_report_ai_email_tasks')
            ->where('sfuser_id', $sfuserId)
            ->whereNull('deleted_at')
            ->orderByDesc('created_at')
            ->get(['id', 'name', 'dimension', 'report_range', 'send_cycle', 'send_time', 'system_prompt', 'is_on', 'created_at']);

        return $this->responseJsonSuccess(['list' => $list]);
    }

    public function taskCreate(Request $request): JsonResponse
    {
        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
        if (!$this->inWhitelist($sfuserId)) {
            return $this->responseJsonFail('无权限');
        }

        $input = Arr::only($request->all(), ['name', 'dimension', 'report_range', 'send_cycle', 'send_time', 'system_prompt']);

        $id = DB::table('daily_report_ai_email_tasks')->insertGetId([
            'sfuser_id' => $sfuserId,
            'name' => $input['name'],
            'dimension' => $input['dimension'] ?? 'department',
            'report_range' => $input['report_range'] ?? 'today',
            'send_cycle' => $input['send_cycle'] ?? 'daily',
            'send_time' => $input['send_time'] ?? '09:00',
            'system_prompt' => $input['system_prompt'] ?? '',
            'is_on' => 1,
            'created_at' => now(),
            'updated_at' => now(),
        ]);

        return $this->responseJsonSuccess(['id' => $id]);
    }

    public function taskUpdate(Request $request): JsonResponse
    {
        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
        if (!$this->inWhitelist($sfuserId)) {
            return $this->responseJsonFail('无权限');
        }

        $id = $request->input('id');
        $input = Arr::only($request->all(), ['name', 'dimension', 'report_range', 'send_cycle', 'send_time', 'system_prompt']);

        $affected = DB::table('daily_report_ai_email_tasks')
            ->where('id', $id)
            ->where('sfuser_id', $sfuserId)
            ->whereNull('deleted_at')
            ->update(array_merge(
                array_filter($input, fn ($v) => $v !== null),
                ['updated_at' => now()]
            ));

        return $this->responseJsonSuccess(['affected' => $affected]);
    }

    public function taskDelete(Request $request): JsonResponse
    {
        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
        if (!$this->inWhitelist($sfuserId)) {
            return $this->responseJsonFail('无权限');
        }

        DB::table('daily_report_ai_email_tasks')
            ->where('id', $request->input('id'))
            ->where('sfuser_id', $sfuserId)
            ->whereNull('deleted_at')
            ->update(['deleted_at' => now()]);

        return $this->responseJsonSuccess();
    }

    public function taskToggle(Request $request): JsonResponse
    {
        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
        if (!$this->inWhitelist($sfuserId)) {
            return $this->responseJsonFail('无权限');
        }

        $id = $request->input('id');
        $isOn = $request->input('is_on');

        DB::table('daily_report_ai_email_tasks')
            ->where('id', $id)
            ->where('sfuser_id', $sfuserId)
            ->whereNull('deleted_at')
            ->update(['is_on' => $isOn, 'updated_at' => now()]);

        return $this->responseJsonSuccess();
    }
}
```

